+pub const c_int_buffer = struct {
+    const Self = @This();
+
+    ptr: *align(1) i32,
+
+    pub fn fromBuffer(buffer: []u8) !Self {
+        if (buffer.len < 4) return error.BufferTooSmall;
+        return .{ .ptr = @ptrCast(buffer.ptr) };
+    }
+
+    pub fn value(self: Self) i32 {
+        return self.ptr.*;
+    }
+
+    pub fn setValue(self: Self, v: i32) void {
+        self.ptr.* = v;
+    }
+};
