+    pub fn init(ptr: *const anyopaque) Self {
+        return .{ .ptr = ptr };
+    }
+
+    pub fn withUserData(ptr: *const anyopaque, data: *anyopaque) Self {
+        return .{ .ptr = ptr, .user_data = data };
+    }
+
+    pub fn address(self: Self) usize {
+        return @intFromPtr(self.ptr);
+    }
+};
