+const std = @import("std");
+const _support = @import("_support.zig");
+
+pub const c_byte = i8;
+pub const c_ubyte = u8;
+pub const c_short = i16;
+pub const c_ushort = u16;
+pub const c_int = i32;
+pub const c_uint = u32;
+pub const c_long = i64;
