+    const str = "Hello";
+    const cp = c_char_p.init(str.ptr);
+    try std.testing.expect(!cp.isNull());
+}
+
+test "string_buffer" {
+    var buf = create_string_buffer(100);
+    buf.set("Test");
+    try std.testing.expectEqualStrings("Test", buf.value());
+}

