+    var arr = try VarSizeArray(i32).init(std.testing.allocator, 10);
+    defer arr.deinit();
+    try std.testing.expectEqual(@as(usize, 10), arr.len());
+    arr.set(0, 42);
+    try std.testing.expectEqual(@as(?i32, 42), arr.get(0));
